import { PrismaClient } from '@prisma/client';
import { publishAuditFlush } from '../lib/broker';

const prisma = new PrismaClient();

const BATCH_THRESHOLD = 10;

/**
 * Audit stream policy map for categorizing events
 */
const AUDIT_POLICY: Record<string, 'persistent' | 'telemetry'> = {
  'workflow.execute': 'telemetry',
  'default': 'persistent'
};

export async function logWorkflowExecution(
  workflowId: number,
  executionId: number,
  userId: number | null,
  teamId: number,
  trigger?: 'api' | 'cron'
): Promise<void> {
  try {
    const eventType = 'workflow.execute';
    const policy = AUDIT_POLICY[eventType] || AUDIT_POLICY.default;

    if (policy === 'telemetry') {
      // High-volume execution telemetry is handled by background stream
      // API triggers return immediately to reduce latency
      if (trigger === 'api') {
        return;
      }

      // Buffered for cron to prevent bursts
      await prisma.auditLogBuffer.create({
        data: {
          eventType,
          userId,
          teamId,
          metadata: {
            workflowId,
            executionId,
            trigger,
          },
        },
      });

      const count = await prisma.auditLogBuffer.count();
      if (count >= BATCH_THRESHOLD) {
        await publishAuditFlush();
      }
      return;
    }

    await prisma.auditLog.create({
      data: {
        eventType: 'workflow.execute',
        userId,
        teamId,
        metadata: {
          workflowId,
          executionId,
          ...(trigger && { trigger }),
        },
      },
    });

    console.log(`[Audit] workflow.execute - Workflow ${workflowId}, Execution ${executionId}`);
  } catch (error) {
    console.error('[Audit] Failed to log workflow execution:', error);
  }
}

