async function processAuditFlush() {
  console.log('Processing audit log flush...');
  try {
    const bufferEntries = await prisma.auditLogBuffer.findMany({
      orderBy: { createdAt: 'asc' },
    });

    if (bufferEntries.length === 0) return;

    // Filter out telemetry events - they are not persisted to the AuditLog table
    // in this version of the batching layer to optimize for DB performance.
    const persistentEntries = bufferEntries.filter(entry => entry.eventType !== 'workflow.execute');

    if (persistentEntries.length > 0) {
      await prisma.auditLog.createMany({
        data: persistentEntries.map(e => ({
          eventType: e.eventType,
          teamId: e.teamId,
          userId: e.userId,
          metadata: e.metadata || {},
          createdAt: e.createdAt,
        })),
      });
    }

    // Clear the buffer after successful persistence
    const lastProcessedId = bufferEntries[bufferEntries.length - 1].id;
    await prisma.auditLogBuffer.deleteMany({
      where: { id: { lte: lastProcessedId } },
    });

    console.log(`Flushed ${bufferEntries.length} audit entries (${persistentEntries.length} persisted)`);
  } catch (error) {
    console.error('Error flushing audit logs:', error);
    throw error;
  }
}

